#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <cuda.h>

#include "../common.h"
#include "../util/timer/timer.h"
#include "./kernel_gpu_cuda_wrapper.h"

#ifdef TIMING
#include "../../util/timing.h"
#endif

extern int platform_id_inuse;
extern int device_id_inuse;

void 
kernel_gpu_cuda_wrapper(	record *records,
							long records_mem,
							knode *knodes,
							long knodes_elem,
							long knodes_mem,
							int order,
							long maxheight,
							int count,
							long *currKnode,
							long *offset,
							int *keys,
							record *ans)
{
#ifdef TIMING
	struct timeval tv;
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_h2d_start, tv_h2d_end;
	struct timeval tv_d2h_start, tv_d2h_end;
	struct timeval tv_kernel_start, tv_kernel_end;
	struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time= 0,
		  d2h_time = 0, close_time = 0, total_time = 0;
#endif

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

	setdevice();

#ifdef TIMING
	gettimeofday(&tv_init_end, NULL);
	tvsub(&tv_init_end, &tv_total_start, &tv);
	init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	knode *knodesD;
	record *recordsD;
	long *currKnodeD;
	long *offsetD;
	int *keysD;
	record *ansD;

#ifdef TIMING
	gettimeofday(&tv_mem_alloc_start, NULL);
#endif

	cudaError_t err;
	err = cudaMalloc((void**)&recordsD, records_mem);
	if(err != cudaSuccess) { fprintf(stderr, "cudaMalloc recordsD failed\n"); exit(1); }

	err = cudaMalloc((void**)&knodesD, knodes_mem);
	if(err != cudaSuccess) { fprintf(stderr, "cudaMalloc knodesD failed\n"); exit(1); }

	err = cudaMalloc((void**)&currKnodeD, count*sizeof(long));
	if(err != cudaSuccess) { fprintf(stderr, "cudaMalloc currKnodeD failed\n"); exit(1); }

	err = cudaMalloc((void**)&offsetD, count*sizeof(long));
	if(err != cudaSuccess) { fprintf(stderr, "cudaMalloc offsetD failed\n"); exit(1); }

	err = cudaMalloc((void**)&keysD, count*sizeof(int));
	if(err != cudaSuccess) { fprintf(stderr, "cudaMalloc keysD failed\n"); exit(1); }

	err = cudaMalloc((void**)&ansD, count*sizeof(record));
	if(err != cudaSuccess) { fprintf(stderr, "cudaMalloc ansD failed\n"); exit(1); }

#ifdef TIMING
	gettimeofday(&tv_mem_alloc_end, NULL);
	tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
	mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
	gettimeofday(&tv_h2d_start, NULL);
#endif

	err = cudaMemcpy(recordsD, records, records_mem, cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { fprintf(stderr, "cudaMemcpy records failed\n"); exit(1); }

	err = cudaMemcpy(knodesD, knodes, knodes_mem, cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { fprintf(stderr, "cudaMemcpy knodes failed\n"); exit(1); }

	err = cudaMemcpy(currKnodeD, currKnode, count*sizeof(long), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { fprintf(stderr, "cudaMemcpy currKnode failed\n"); exit(1); }

	err = cudaMemcpy(offsetD, offset, count*sizeof(long), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { fprintf(stderr, "cudaMemcpy offset failed\n"); exit(1); }

	err = cudaMemcpy(keysD, keys, count*sizeof(int), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { fprintf(stderr, "cudaMemcpy keys failed\n"); exit(1); }

	err = cudaMemcpy(ansD, ans, count*sizeof(record), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { fprintf(stderr, "cudaMemcpy ans init failed\n"); exit(1); }

#ifdef TIMING
	gettimeofday(&tv_h2d_end, NULL);
	tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
	h2d_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	size_t local_work_size = order < 1024 ? order : 1024;
	size_t global_work_size = count * local_work_size;

	printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n", (int)(global_work_size/local_work_size), (int)local_work_size);

#ifdef TIMING
	gettimeofday(&tv_kernel_start, NULL);
#endif

	findK(maxheight, knodesD, knodes_elem, recordsD, currKnodeD, offsetD, keysD, ansD);

	checkCUDAError("Kernel execution");

#ifdef TIMING
	gettimeofday(&tv_kernel_end, NULL);
	tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
	kernel_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
	gettimeofday(&tv_d2h_start, NULL);
#endif

	err = cudaMemcpy(ans, ansD, count*sizeof(record), cudaMemcpyDeviceToHost);
	if(err != cudaSuccess) { fprintf(stderr, "cudaMemcpy ans result failed\n"); exit(1); }

#ifdef TIMING
	gettimeofday(&tv_d2h_end, NULL);
	tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
	d2h_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

	cudaFree(recordsD);
	cudaFree(knodesD);
	cudaFree(currKnodeD);
	cudaFree(offsetD);
	cudaFree(keysD);
	cudaFree(ansD);

#ifdef TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif
}

